module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

    always @(*) begin
        if (B == 0) begin
            result = 16'hFFFF; 
            odd = A; 
        end
        else begin
            result = A / B; 
            odd = A % B; 
        end
    end

endmodule
